"use strict";(self.webpackChunkstudy_journal=self.webpackChunkstudy_journal||[]).push([["655"],{389(e,n,t){t.r(n),t.d(n,{metadata:()=>a,default:()=>u,frontMatter:()=>l,contentTitle:()=>o,toc:()=>c,assets:()=>r});var a=JSON.parse('{"id":"DevSecOps/yaml","title":"Notes on YAML","description":"Basics","source":"@site/docs/DevSecOps/yaml.mdx","sourceDirName":"DevSecOps","slug":"/DevSecOps/yaml","permalink":"/study-journal/docs/DevSecOps/yaml","draft":false,"unlisted":false,"editUrl":"https://github.com/lima-emanuel/study-journal/tree/main/packages/create-docusaurus/templates/shared/docs/DevSecOps/yaml.mdx","tags":[],"version":"current","sidebarPosition":8,"frontMatter":{"sidebar_position":8},"sidebar":"tutorialSidebar","previous":{"title":"Notes on Redis","permalink":"/study-journal/docs/DevSecOps/redis"},"next":{"title":"Operating Systems","permalink":"/study-journal/docs/category/operating-systems"}}'),i=t(1684),s=t(506);let l={sidebar_position:8},o="Notes on YAML",r={},c=[{value:"Basics",id:"basics",level:2}];function d(e){let n={code:"code",h1:"h1",h2:"h2",header:"header",p:"p",pre:"pre",...(0,s.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.header,{children:(0,i.jsx)(n.h1,{id:"notes-on-yaml",children:"Notes on YAML"})}),"\n",(0,i.jsx)(n.h2,{id:"basics",children:"Basics"}),"\n",(0,i.jsx)(n.p,{children:"YAML is a human-readable data serialization language. It is used for configuration files and in applications where data is being stored or transmitted."}),"\n",(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{className:"language-yaml",children:"---  # document start\n\n# Comments in YAML look like this.\n# YAML supports single-line comments.\n\n################\n# SCALAR TYPES #\n################\n\n# Our root object (which continues for the entire document) will be a map,\n# which is equivalent to a dictionary, hash or object in other languages.\nkey: value\nanother_key: Another value goes here.\na_number_value: 100\nscientific_notation: 1e+12\nhex_notation: 0x123  # evaluates to 291\noctal_notation: 0123 # evaluates to 83\n\n# The number 1 will be interpreted as a number, not a boolean.\n# If you want it to be interpreted as a boolean, use true.\nboolean: true\nnull_value: null\nanother_null_value: ~\nkey with spaces: value\n\n# Yes and No (doesn't matter the case) will be evaluated to boolean\n# true and false values respectively.\n# To use the actual value use single or double quotes.\nno: no            # evaluates to \"no\": false\nyes: No           # evaluates to \"yes\": false\nnot_enclosed: yes # evaluates to \"not_enclosed\": true\nenclosed: \"yes\"   # evaluates to \"enclosed\": yes\n\n# Notice that strings don't need to be quoted. However, they can be.\nhowever: 'A string, enclosed in quotes.'\n'Keys can be quoted too.': \"Useful if you want to put a ':' in your key.\"\nsingle quotes: 'have ''one'' escape pattern'\ndouble quotes: \"have many: \\\", \\0, \\t, \\u263A, \\x0d\\x0a == \\r\\n, and more.\"\n# UTF-8/16/32 characters need to be encoded\nSuperscript two: \\u00B2\n\n# Special characters must be enclosed in single or double quotes\nspecial_characters: \"[ John ] & { Jane } - <Doe>\"\n\n# Multiple-line strings can be written either as a 'literal block' (using |),\n# or a 'folded block' (using '>').\n# Literal block turn every newline within the string into a literal newline (\\n).\n# Folded block removes newlines within the string.\nliteral_block: |\n  This entire block of text will be the value of the 'literal_block' key,\n  with line breaks being preserved.\n\n  The literal continues until de-dented, and the leading indentation is\n  stripped.\n\n      Any lines that are 'more-indented' keep the rest of their indentation -\n      these lines will be indented by 4 spaces.\nfolded_style: >\n  This entire block of text will be the value of 'folded_style', but this\n  time, all newlines will be replaced with a single space.\n\n  Blank lines, like above, are converted to a newline character.\n\n      'More-indented' lines keep their newlines, too -\n      this text will appear over two lines.\n\n# |- and >- removes the trailing blank lines (also called literal/block \"strip\")\nliteral_strip: |-\n  This entire block of text will be the value of the 'literal_strip' key,\n  with trailing blank line being stripped.\nblock_strip: >-\n  This entire block of text will be the value of 'block_strip', but this\n  time, all newlines will be replaced with a single space and\n  trailing blank line being stripped.\n\n# |+ and >+ keeps trailing blank lines (also called literal/block \"keep\")\nliteral_keep: |+\n  This entire block of text will be the value of the 'literal_keep' key,\n  with trailing blank line being kept.\n\nblock_keep: >+\n  This entire block of text will be the value of 'block_keep', but this\n  time, all newlines will be replaced with a single space and\n  trailing blank line being kept.\n\n####################\n# COLLECTION TYPES #\n####################\n\n# Nesting uses indentation. 2 space indent is preferred (but not required).\na_nested_map:\n  key: value\n  another_key: Another Value\n  another_nested_map:\n    hello: hello\n\n# Maps don't have to have string keys.\n0.25: a float key\n\n# Keys can also be complex, like multi-line objects\n# We use ? followed by a space to indicate the start of a complex key.\n? |\n  This is a key\n  that has multiple lines\n: and this is its value\n\n# YAML also allows mapping between sequences with the complex key syntax\n# Some language parsers might complain\n# An example\n? - Manchester United\n  - Real Madrid\n: [ 2001-01-01, 2002-02-02 ]\n\n# Sequences (equivalent to lists or arrays) look like this\n# (note that the '-' counts as indentation):\na_sequence:\n  - Item 1\n  - Item 2\n  - 0.5  # sequences can contain disparate types.\n  - Item 4\n  - key: value\n    another_key: another_value\n  - - This is a sequence\n    - inside another sequence\n  - - - Nested sequence indicators\n      - can be collapsed\n\n# Since YAML is a superset of JSON, you can also write JSON-style maps and\n# sequences:\njson_map: { \"key\": \"value\" }\njson_seq: [ 3, 2, 1, \"takeoff\" ]\nand quotes are optional: { key: [ 3, 2, 1, takeoff ] }\n\n#######################\n# EXTRA YAML FEATURES #\n#######################\n\n# YAML also has a handy feature called 'anchors', which let you easily duplicate\n# content across your document.\n# Anchors identified by & character which define the value.\n# Aliases identified by * character which acts as \"see above\" command.\n# Both of these keys will have the same value:\nanchored_content: &anchor_name This string will appear as the value of two keys.\nother_anchor: *anchor_name\n\n# Anchors can be used to duplicate/inherit properties\nbase: &base\n  name: Everyone has same name\n\n# The expression << is called 'Merge Key Language-Independent Type'. It is used to\n# indicate that all the keys of one or more specified maps should be inserted\n# into the current map.\n# NOTE: If key already exists alias will not be merged\nfoo:\n  <<: *base # doesn't merge the anchor\n  age: 10\n  name: John\nbar:\n  <<: *base # base anchor will be merged\n  age: 20\n\n# foo name won't be changed and it will be: John. On the other hand, bar's name will be changed to the base one: Everyone has same name\n\n# YAML also has tags, which you can use to explicitly declare types.\n# Syntax: !![typeName] [value]\nexplicit_boolean: !!bool true\nexplicit_integer: !!int 42\nexplicit_float: !!float -42.24\nexplicit_string: !!str 0.5\nexplicit_datetime: !!timestamp 2022-11-17 12:34:56.78 +9\nexplicit_null: !!null null\n\n# Some parsers implement language specific tags, like this one for Python's\n# complex number type.\npython_complex_number: !!python/complex 1+2j\n\n# We can also use yaml complex keys with language specific tags\n? !!python/tuple [ 5, 7 ]\n: Fifty Seven\n# Would be {(5, 7): 'Fifty Seven'} in Python\n\n####################\n# EXTRA YAML TYPES #\n####################\n\n# Strings and numbers aren't the only scalars that YAML can understand.\n# ISO-formatted date and datetime literals are also parsed.\ndatetime_canonical: 2001-12-15T02:59:43.1Z\ndatetime_space_separated_with_time_zone: 2001-12-14 21:59:43.10 -5\ndate_implicit: 2002-12-14\ndate_explicit: !!timestamp 2002-12-14\n\n# The !!binary tag indicates that a string is actually a base64-encoded\n# representation of a binary blob.\ngif_file: !!binary |\n  R0lGODlhDAAMAIQAAP//9/X17unp5WZmZgAAAOfn515eXvPz7Y6OjuDg4J+fn5\n  OTk6enp56enmlpaWNjY6Ojo4SEhP/++f/++f/++f/++f/++f/++f/++f/++f/+\n  +f/++f/++f/++f/++f/++SH+Dk1hZGUgd2l0aCBHSU1QACwAAAAADAAMAAAFLC\n  AgjoEwnuNAFOhpEMTRiggcz4BNJHrv/zCFcLiwMWYNG84BwwEeECcgggoBADs=\n\n# YAML also has a set type, which looks like this:\nset:\n  ? item1\n  ? item2\n  ? item3\nor: { item1, item2, item3 }\n\n# Sets are just maps with null values; the above is equivalent to:\nset2:\n  item1: null\n  item2: null\n  item3: null\n\n...  # document end\n"})})]})}function u(e={}){let{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},506(e,n,t){t.d(n,{R:()=>l,x:()=>o});var a=t(2888);let i={},s=a.createContext(i);function l(e){let n=a.useContext(s);return a.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function o(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:l(e.components),a.createElement(s.Provider,{value:n},e.children)}}}]);